import{_ as t,c as o,o as a,a5 as r}from"./chunks/framework.CgT1UzWm.js";const m=JSON.parse('{"title":"Changelog v3.18.2","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog/v3.18.2.md","filePath":"guide/changelog/v3.18.2.md"}'),s={name:"guide/changelog/v3.18.2.md"};function n(d,e,i,c,l,p){return a(),o("div",null,e[0]||(e[0]=[r('<h1 id="changelog-v3-18-2" tabindex="-1">Changelog v3.18.2 <a class="header-anchor" href="#changelog-v3-18-2" aria-label="Permalink to &quot;Changelog v3.18.2&quot;">​</a></h1><h2 id="version-3-18-2-2026-06-26" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.18.2" target="_blank" rel="noreferrer">3.18.2</a> (2026-06-26) <a class="header-anchor" href="#version-3-18-2-2026-06-26" aria-label="Permalink to &quot;Version [3.18.2](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.18.2) (2026-06-26)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.18.1...3.18.2" target="_blank" rel="noreferrer">Full Changelog</a></p><p>Patch release with fixes for <strong>proxy endpoints that forward auto-filled parameters</strong> (v3.18.1) and the generated TypeScript client, plus a new opt-in option to <strong>omit server-filled parameters from generated request shapes</strong>. All surfaced by combining a <code>@proxy</code> with an HTTP Custom Type parameter.</p><h2 id="what-changed" tabindex="-1">What changed <a class="header-anchor" href="#what-changed" aria-label="Permalink to &quot;What changed&quot;">​</a></h2><h3 id="_1-large-auto-filled-values-no-longer-break-the-proxy-query-string" tabindex="-1">1. Large auto-filled values no longer break the proxy query string <a class="header-anchor" href="#_1-large-auto-filled-values-no-longer-break-the-proxy-query-string" aria-label="Permalink to &quot;1. Large auto-filled values no longer break the proxy query string&quot;">​</a></h3><p>New option <strong><code>ProxyOptions.MaxForwardedQueryParamLength</code></strong> (default <code>2048</code>). When a server-filled parameter is appended to the proxy upstream <strong>query string</strong>, a value longer than this limit is now <strong>skipped with a warning</strong> instead of being percent-encoded into the URL.</p><p>Previously, an HTTP Custom Type whose <code>body</code> field held a large payload (e.g. a scraped HTML page) was percent-encoded into the upstream query string, producing an oversized request line that the upstream rejected (HTTP 414 / 431) or that reset the connection. To forward such a value, use a body-carrying proxy method (POST/PUT/PATCH) so it travels in the request body instead. Set the option to <code>0</code> to disable the guard.</p><h3 id="_2-body-parameter-name-reliably-matches-http-custom-type-fields" tabindex="-1">2. <code>@body_parameter_name</code> reliably matches HTTP Custom Type fields <a class="header-anchor" href="#_2-body-parameter-name-reliably-matches-http-custom-type-fields" aria-label="Permalink to &quot;2. `@body_parameter_name` reliably matches HTTP Custom Type fields&quot;">​</a></h3><p><code>@body_parameter_name</code> now matches <strong>case-insensitively</strong> and accepts any of the parameter&#39;s names. For an HTTP Custom Type field expanded out of a composite parameter, all of these now resolve to the same field:</p><ul><li>the <strong>converted (API) name</strong> — e.g. <code>responseBody</code></li><li>the <strong>expanded signature name</strong> — e.g. <code>_response_body</code> (the name shown in the generated signature / <code>.http</code> file)</li><li>the <strong>base composite name</strong> — e.g. <code>_response</code> (shared by all expanded fields; resolves to the first one)</li></ul><p>Previously the annotation value was force-lowercased and compared case-sensitively, so the camelCase converted name never matched, and the expanded signature name (<code>_response_body</code>) matched nothing at all — it is stored as neither the actual nor the converted name. This made it impossible to redirect a single expanded HTTP-type field (such as the response body) into the proxy request body.</p><p>Body-parameter resolution is now a single shared rule on the core endpoint (<code>RoutineEndpoint.IsBodyParameter</code>) used by request handling <strong>and</strong> every code generator, so they no longer drift. This also fixes the <strong>HTTP file</strong> and <strong>OpenAPI</strong> generators, which previously left a <code>@body_parameter_name</code> field (e.g. <code>responseBody</code>) in the query string / query parameters instead of moving it to the request body.</p><h3 id="_3-typescript-client-generation-for-body-parameter-name" tabindex="-1">3. TypeScript client generation for <code>@body_parameter_name</code> <a class="header-anchor" href="#_3-typescript-client-generation-for-body-parameter-name" aria-label="Permalink to &quot;3. TypeScript client generation for `@body_parameter_name`&quot;">​</a></h3><p>The generated TypeScript client was broken for an endpoint with <code>@body_parameter_name</code>:</p><ul><li>the body expression was emitted as <code>request.responseBody?</code> — a syntax error (the TS optional <code>?</code> suffix leaked into the runtime property name);</li><li>the query-string exclusion key was <code>[&quot;responseBody?&quot;]</code>, so the body parameter was <strong>not</strong> stripped from the query string;</li><li>a <code>body</code> was emitted even for a <code>GET</code> request, which <code>fetch</code> forbids.</li></ul><p>The generator now uses the parameter&#39;s bare name for the body expression and the exclusion key, only emits a <code>fetch</code> body for methods that can carry one (not <code>GET</code>), and — like the server — matches <code>@body_parameter_name</code> against the converted, actual, or expanded signature name of an HTTP Custom Type field (e.g. <code>responseBody</code>, <code>_response</code>, or <code>_response_body</code>).</p><h3 id="_4-opt-in-omit-automatic-server-filled-parameters-from-generated-request-shapes" tabindex="-1">4. Opt-in: omit automatic (server-filled) parameters from generated request shapes <a class="header-anchor" href="#_4-opt-in-omit-automatic-server-filled-parameters-from-generated-request-shapes" aria-label="Permalink to &quot;4. Opt-in: omit automatic (server-filled) parameters from generated request shapes&quot;">​</a></h3><p>New option <strong><code>OmitAutomaticParameters</code></strong> on all three generators — <code>TsClientOptions</code>, <code>HttpFileOptions</code>, and <code>OpenApiOptions</code> (default <strong><code>false</code></strong>, so generated output is unchanged unless you opt in).</p><p>When enabled, a parameter is omitted from the generated request (TypeScript request interface, <code>.http</code> query/body, OpenAPI query parameters / request body) when it is <strong>automatic</strong> (filled server-side, so a client value would be ignored) <strong>and</strong> optional. Automatic covers: HTTP Custom Type fields, resolved-parameter expressions, upload-metadata parameters, and — on endpoints that use user parameters — IP-address and user-claim parameters. The shared rule lives on the core endpoint (<code>RoutineEndpoint.OmitParameterFromGeneratedRequest</code>), so the three generators stay consistent. When every parameter is omitted, the generated request collapses cleanly (no-argument TS function, bare <code>.http</code> URL, no OpenAPI <code>parameters</code>/<code>requestBody</code>).</p><p>This is the proper fix for the misleading case where, e.g., an HTTP Custom Type&#39;s <code>responseBody</code> field appeared as a settable request parameter even though the server always overrides it.</p><h3 id="why-these-go-together" tabindex="-1">Why these go together <a class="header-anchor" href="#why-these-go-together" aria-label="Permalink to &quot;Why these go together&quot;">​</a></h3><p>The pattern &quot;fetch with an HTTP Custom Type, then <code>@proxy</code> to an upstream&quot; now works cleanly end to end — server <strong>and</strong> generated client: redirect the (large) body field into the upstream request body with <code>@body_parameter_name</code>, while the remaining small fields travel on the query string under the new length guard.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><code>ProxyOptions.MaxForwardedQueryParamLength</code> is wired through the client config (<code>appsettings.json</code>, JSON schema, and the <code>--config</code> template).</li><li>No parameter <code>ActualName</code> semantics changed: expanded HTTP-type fields still share the composite base name so they reassemble into the single SQL argument; the per-field name is matched via an internal alias only.</li></ul><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><p><code>NpgsqlRestTests/ProxyTests/ProxyHttpTypeProbeTest.cs</code> adds three cases (WireMock proxy target echoing the received URL / body): body redirect by converted name (<code>responseBody</code>), body redirect by expanded signature name (<code>_response_body</code>), and an oversized HTTP-type body field skipped from the proxy query string. <code>NpgsqlRestTests/TsClientTests/BodyParamGetTests.cs</code> covers the generated client for <code>@body_parameter_name</code> endpoints: a <code>GET</code> case (no <code>?</code>-suffixed name, parameter excluded from the query, no <code>fetch</code> body on <code>GET</code>) and a <code>POST</code> HTTP-Custom-Type case targeted by the expanded name <code>_response_body</code> (body emitted as <code>request.responseBody</code>, excluded from the query). The HTTP file and OpenAPI generators are covered for the same expanded-name body redirect (<code>BodyParamToBodyTests</code>). <code>OmitAutomaticParameters</code> is covered for each generator (TsClient: all-omitted no-arg function + mixed-params; HttpFiles and OpenAPI: query/body omission of HTTP Custom Type fields). Full suite green (2301).</p>',27)]))}const g=t(s,[["render",n]]);export{m as __pageData,g as default};
